135вҶ’		break;
136вҶ’	case EUnitRange::UR_Move:
137вҶ’		SpriteComponent->SetSprite(MovementRangeSprite);
138вҶ’		break;
139вҶ’	case EUnitRange::UR_Attack:
140вҶ’		SpriteComponent->SetSprite(AttackRangeSprite);
141вҶ’		break;
142вҶ’	case EUnitRange::UR_SkillEffect:
143вҶ’		SpriteComponent->SetSprite(SkillEffectRangeSprite);
144вҶ’	default:
145вҶ’		break;
146вҶ’	}
