 17вҶ’USTRUCT(BlueprintType)
 18вҶ’struct FLFPHexCoordinates
 19вҶ’{
 20вҶ’	GENERATED_USTRUCT_BODY()
 21вҶ’
 22вҶ’public:
 23вҶ’	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HexCoordinates")
 24вҶ’	int32 Q; // з«Ӣж–№еқҗж Ү q
 25вҶ’
 26вҶ’	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HexCoordinates")
 27вҶ’	int32 R; // з«Ӣж–№еқҗж Ү r
 28вҶ’
 29вҶ’	UPROPERTY(EditAnywhere, BlueprintReadWrite, Category = "HexCoordinates")
 30вҶ’	int32 S; // з«Ӣж–№еқҗж Ү sпјҲиҮӘеҠЁи®Ўз®—пјү
 31вҶ’
 32вҶ’	FLFPHexCoordinates() : Q(0), R(0), S(0) {}
 33вҶ’
 34вҶ’	FLFPHexCoordinates(int32 q, int32 r) : Q(q), R(r), S(-q - r) {}
 35вҶ’
 36вҶ’	// еқҗж ҮиҪ¬жҚўеҮҪж•°
 37вҶ’	FVector ToWorldLocation(float Size, float VerticalScale = 1.0f) const
 38вҶ’	{
 39вҶ’		// е№ійЎ¶е…ӯиҫ№еҪўеёғеұҖ
 40вҶ’		const float HorizontalSpacing = Size * FMath::Sqrt(3.f); // ж°ҙе№ій—ҙи·қ
 41вҶ’		const float VerticalSpacing = Size * 1.5f * VerticalScale; // еһӮзӣҙй—ҙи·қпјҲеә”з”Ёзј©ж”ҫпјү
 42вҶ’
 43вҶ’		float X = HorizontalSpacing * (Q + R * 0.5f);
 44вҶ’		float Y = VerticalSpacing * R;
 45вҶ’
 46вҶ’		return FVector(X, Y, 0);
 47вҶ’	}
 48вҶ’
 49вҶ’	// и®Ўз®—и·қзҰ»
 50вҶ’	static int32 Distance(const FLFPHexCoordinates& A, const FLFPHexCoordinates& B)
 51вҶ’	{
 52вҶ’		return (FMath::Abs(A.Q - B.Q) +
 53вҶ’			FMath::Abs(A.R - B.R) +
 54вҶ’			FMath::Abs(A.S - B.S)) / 2;
 55вҶ’	}
 56вҶ’
 57вҶ’	// иҺ·еҸ–жүҖжңүзӣёйӮ»еқҗж Ү
 58вҶ’	TArray<FLFPHexCoordinates> GetNeighbors() const
 59вҶ’	{
 60вҶ’		// е…ӯиҫ№еҪўзҡ„йӮ»еұ…ж–№еҗ‘
 61вҶ’		static const TArray<FLFPHexCoordinates> Directions = {
 62вҶ’			FLFPHexCoordinates(+1,  0), // дёң
 63вҶ’			FLFPHexCoordinates(+1, -1), // дёңеҢ—
 64вҶ’			FLFPHexCoordinates(0, -1), // иҘҝеҢ—
 65вҶ’			FLFPHexCoordinates(-1,  0), // иҘҝ
 66вҶ’			FLFPHexCoordinates(-1, +1), // иҘҝеҚ—
 67вҶ’			FLFPHexCoordinates(0, +1)  // дёңеҚ—
 68вҶ’		};
 69вҶ’
 70вҶ’		TArray<FLFPHexCoordinates> Neighbors;
 71вҶ’		for (const auto& Dir : Directions)
 72вҶ’		{
 73вҶ’			Neighbors.Add(FLFPHexCoordinates(Q + Dir.Q, R + Dir.R));
 74вҶ’		}
 75вҶ’		return Neighbors;
 76вҶ’	}
 77вҶ’
 78вҶ’	static FLFPHexCoordinates FromWorldLocation(const FVector2D& WorldLocation, float HexSize, float VerticalScale)
 79вҶ’	{
 80вҶ’		// е№ійЎ¶е…ӯиҫ№еҪўеқҗж ҮиҪ¬жҚўе…¬ејҸ
 81вҶ’		const float Sqrt3 = FMath::Sqrt(3.f);
 82вҶ’
 83вҶ’		float unit_x = HexSize * Sqrt3;
 84вҶ’		float unit_y = HexSize * 1.5f;
 85вҶ’		float minDistanceLimit = HexSize * Sqrt3 * 0.5f;
 86вҶ’		float WorldLocation_X = WorldLocation.X;
 87вҶ’		float WorldLocation_Y = WorldLocation.Y / VerticalScale;
 88вҶ’
 89вҶ’		TArray<FVector2D> anchors;
 90вҶ’		anchors.Add(FVector2D::ZeroVector);
 91вҶ’		anchors.Add(FVector2D::ZeroVector);
 92вҶ’		anchors.Add(FVector2D::ZeroVector);
 93вҶ’		float distance;
 94вҶ’		float minDistance = 10000;
 95вҶ’		int index = 0;
 96вҶ’
 97вҶ’		int32 index_x = WorldLocation_X / unit_x - (WorldLocation_X < 0 ? 1 : 0);
 98вҶ’		int32 index_y = WorldLocation_Y / unit_y - (WorldLocation_Y < 0 ? 1 : 0);
 99вҶ’		anchors[0].X = index_x * unit_x;
100вҶ’		anchors[1].X = (index_x + 0.5) * unit_x;
101вҶ’		anchors[2].X = (index_x + 1) * unit_x;
102вҶ’		if (index_y % 2 == 0)
103вҶ’		{
104вҶ’			anchors[0].Y = anchors[2].Y = index_y * unit_y;
105вҶ’			anchors[1].Y = (index_y + 1) * unit_y;
106вҶ’		}
107вҶ’		else
108вҶ’		{
109вҶ’			anchors[0].Y = anchors[2].Y = (index_y + 1) * unit_y;
110вҶ’			anchors[1].Y = index_y * unit_y;
111вҶ’		}
112вҶ’		// жүҫеҮәи·қзҰ»зӮ№жңҖиҝ‘зҡ„дёҖдёӘй”ҡзӮ№
113вҶ’		for (int i = 0; i < 3; i++)
114вҶ’		{
115вҶ’			// и®Ўз®—ж¬§ејҸи·қзҰ»
116вҶ’			//UE_LOG(LogTemp, Warning, TEXT("anchor:(%f,%f)"), anchors[i].X, anchors[i].Y);
117вҶ’			distance = FVector2D::Distance(FVector2D(WorldLocation_X, WorldLocation_Y), FVector2D(anchors[i].X, anchors[i].Y));
118вҶ’			//UE_LOG(LogTemp, Warning, TEXT("distance:(%f)"), distance);
119вҶ’			// еҰӮжһңе·Із»ҸеҚҒеҲҶзЎ®е®ҡдәҶ
120вҶ’			if (distance < minDistanceLimit)
121вҶ’			{
122вҶ’				index = i;
123вҶ’				break;
124вҶ’			}
125вҶ’
126вҶ’			// и®°еҪ•жңҖе°Ҹи·қзҰ»е’Ңзҙўеј•
127вҶ’			if (distance < minDistance)
128вҶ’			{
129вҶ’				minDistance = distance;
130вҶ’				index = i;
131вҶ’			}
132вҶ’		}
133вҶ’
134вҶ’		int32 q = FMath::RoundToFloat((anchors[index].X / Sqrt3 - anchors[index].Y / 3.f) / HexSize);
135вҶ’		int32 r = FMath::RoundToFloat(anchors[index].Y * 2.f / 3.f / HexSize);
136вҶ’
137вҶ’		return FLFPHexCoordinates(q, r);
138вҶ’	}
139вҶ’};
