106вҶ’ALFPHexTile* ALFPHexGridManager::SpawnTileAt(int32 Q, int32 R, ELFPTerrainType TerrainType,
107вҶ’	FName DecorationID, ELFPSpawnFaction SpawnFaction, int32 SpawnIndex, FGameplayTag EventTag)
108вҶ’{
109вҶ’	FIntPoint Key(Q, R);
110вҶ’	// еҰӮжһңе·ІеӯҳеңЁеҲҷи·іиҝҮ
111вҶ’	if (GridMap.Contains(Key)) return GridMap[Key];
112вҶ’
113вҶ’	FLFPHexCoordinates HexCoord(Q, R);
114вҶ’	FVector WorldLocation = HexCoord.ToWorldLocation(HexSize, VerticalScale) + GetActorLocation();
115вҶ’
116вҶ’	FActorSpawnParameters SpawnParams;
117вҶ’	SpawnParams.Owner = this;
118вҶ’	ALFPHexTile* NewTile = GetWorld()->SpawnActor<ALFPHexTile>(
119вҶ’		HexTileClass,
120вҶ’		WorldLocation,
121вҶ’		FRotator::ZeroRotator,
122вҶ’		SpawnParams
123вҶ’	);
124вҶ’
125вҶ’	if (!NewTile) return nullptr;
126вҶ’
127вҶ’	NewTile->SetCoordinates(HexCoord);
128вҶ’	NewTile->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
129вҶ’
130вҶ’	// еә”з”Ёең°еҪўпјҡдјҳе…Ҳд»ҺжіЁеҶҢиЎЁжҹҘжүҫпјҢеҗҰеҲҷз”Ёй»ҳи®Өең°еҪў
131вҶ’	if (ULFPTerrainDataAsset* TerrainDA = GetTerrainDataForType(TerrainType))
132вҶ’	{
133вҶ’		NewTile->SetTerrainData(TerrainDA);
134вҶ’	}
135вҶ’	else if (DefaultTerrainData)
136вҶ’	{
137вҶ’		NewTile->SetTerrainData(DefaultTerrainData);
138вҶ’	}
139вҶ’
140вҶ’	// еә”з”ЁиЈ…йҘ°
141вҶ’	if (!DecorationID.IsNone())
142вҶ’	{
143вҶ’		NewTile->SetDecorationByID(DecorationID, GetDecorationSprite(DecorationID));
144вҶ’	}
145вҶ’
146вҶ’	// еә”з”ЁеҮәз”ҹзӮ№е’ҢдәӢд»¶ж•°жҚ®
147вҶ’	NewTile->SpawnFaction = SpawnFaction;
148вҶ’	NewTile->SpawnIndex = SpawnIndex;
149вҶ’	NewTile->EventTag = EventTag;
150вҶ’
151вҶ’	GridMap.Add(Key, NewTile);
152вҶ’	return NewTile;
153вҶ’}
