227вҶ’bool ALFPHexGridManager::SaveMapToCSV(const FString& CSVFilePath)
228вҶ’{
229вҶ’	// CSV еӨҙйғЁпјҲUE DataTable ж јејҸпјҡз¬¬дёҖеҲ—дёә RowNameпјү
230вҶ’	FString CSVContent = TEXT("---,Q,R,TerrainType,DecorationID,SpawnFaction,SpawnIndex,EventTag\n");
231вҶ’
232вҶ’	for (const auto& Pair : GridMap)
233вҶ’	{
234вҶ’		ALFPHexTile* Tile = Pair.Value;
235вҶ’		if (!Tile) continue;
236вҶ’
237вҶ’		FLFPHexCoordinates Coord = Tile->GetCoordinates();
238вҶ’		FString RowName = FString::Printf(TEXT("%d_%d"), Coord.Q, Coord.R);
239вҶ’
240вҶ’		// ең°еҪўзұ»еһӢжһҡдёҫеҗҚ
241вҶ’		ELFPTerrainType TType = Tile->GetTerrainData() ? Tile->GetTerrainData()->TerrainType : ELFPTerrainType::TT_Grass;
242вҶ’		FString TerrainStr = UEnum::GetValueAsString(TType);
243вҶ’		TerrainStr = TerrainStr.RightChop(TerrainStr.Find(TEXT("::")) + 2);
244вҶ’
245вҶ’		// иЈ…йҘ° ID
246вҶ’		FString DecoStr = Tile->DecorationID.IsNone() ? TEXT("") : Tile->DecorationID.ToString();
247вҶ’
248вҶ’		// еҮәз”ҹзӮ№йҳөиҗҘ
249вҶ’		FString SpawnStr = UEnum::GetValueAsString(Tile->SpawnFaction);
250вҶ’		SpawnStr = SpawnStr.RightChop(SpawnStr.Find(TEXT("::")) + 2);
251вҶ’
252вҶ’		// дәӢд»¶ж Үзӯҫ
253вҶ’		FString EventStr = Tile->EventTag.IsValid() ? Tile->EventTag.ToString() : TEXT("");
254вҶ’
255вҶ’		CSVContent += FString::Printf(TEXT("%s,%d,%d,%s,%s,%s,%d,%s\n"),
256вҶ’			*RowName, Coord.Q, Coord.R, *TerrainStr, *DecoStr,
257вҶ’			*SpawnStr, Tile->SpawnIndex, *EventStr);
258вҶ’	}
259вҶ’
260вҶ’	// зЎ®дҝқзӣ®еҪ•еӯҳеңЁ
261вҶ’	FString Directory = FPaths::GetPath(CSVFilePath);
262вҶ’	if (!FPaths::DirectoryExists(Directory))
263вҶ’	{
264вҶ’		IFileManager::Get().MakeDirectory(*Directory, true);
265вҶ’	}
266вҶ’
267вҶ’	bool bSuccess = FFileHelper::SaveStringToFile(CSVContent, *CSVFilePath,
268вҶ’		FFileHelper::EEncodingOptions::ForceUTF8WithoutBOM);
269вҶ’
270вҶ’	if (bSuccess)
271вҶ’	{
272вҶ’		UE_LOG(LogTemp, Log, TEXT("SaveMapToCSV: дҝқеӯҳ %d дёӘж јеӯҗеҲ° %s"), GridMap.Num(), *CSVFilePath);
273вҶ’	}
274вҶ’	else
275вҶ’	{
276вҶ’		UE_LOG(LogTemp, Error, TEXT("SaveMapToCSV: дҝқеӯҳеӨұиҙҘ %s"), *CSVFilePath);
277вҶ’	}
278вҶ’	return bSuccess;
279вҶ’}
