359вҶ’TArray<ALFPHexTile*> ALFPHexGridManager::GetTilesInRange(ALFPHexTile* Center, int32 MaxRange, int32 MinRange)
360вҶ’{
361вҶ’	TArray<ALFPHexTile*> ReachableTiles;
362вҶ’	if (!Center || MaxRange <= 0) return ReachableTiles;
363вҶ’
364вҶ’	// Dijkstra ж•°жҚ®з»“жһ„пјҲж”ҜжҢҒеҸҳд»Јд»·ең°еҪўпјү
365вҶ’	TMap<ALFPHexTile*, int32> MoveCosts;
366вҶ’	TArray<ALFPHexTile*> OpenList;
367вҶ’
368вҶ’	OpenList.Add(Center);
369вҶ’	MoveCosts.Add(Center, 0);
370вҶ’
371вҶ’	while (OpenList.Num() > 0)
372вҶ’	{
373вҶ’		// жүҫеҲ°д»Јд»·жңҖе°Ҹзҡ„иҠӮзӮ№
374вҶ’		int32 MinCostIndex = 0;
375вҶ’		int32 MinCost = MoveCosts[OpenList[0]];
376вҶ’		for (int32 i = 1; i < OpenList.Num(); i++)
377вҶ’		{
378вҶ’			int32 Cost = MoveCosts[OpenList[i]];
379вҶ’			if (Cost < MinCost)
380вҶ’			{
381вҶ’				MinCost = Cost;
382вҶ’				MinCostIndex = i;
383вҶ’			}
384вҶ’		}
385вҶ’
386вҶ’		ALFPHexTile* CurrentTile = OpenList[MinCostIndex];
387вҶ’		OpenList.RemoveAt(MinCostIndex);
388вҶ’		int32 CurrentCost = MoveCosts[CurrentTile];
389вҶ’
390вҶ’		// иҺ·еҸ–жүҖжңүйӮ»еұ…
391вҶ’		for (ALFPHexTile* Neighbor : GetNeighbors(CurrentTile->GetCoordinates()))
392вҶ’		{
393вҶ’			if (!Neighbor || !Neighbor->IsWalkable() || Neighbor->IsOccupied()) continue;
394вҶ’
395вҶ’			// и®Ўз®—з§»еҠЁд»Јд»·пјҲдҪҝз”Ёең°еҪўд»Јд»·пјү
396вҶ’			const int32 NewCost = CurrentCost + Neighbor->GetMovementCost();
397вҶ’
398вҶ’			// еҰӮжһңжңӘи®ҝй—®жҲ–жүҫеҲ°жӣҙзҹӯи·Ҝеҫ„
399вҶ’			if (!MoveCosts.Contains(Neighbor) || NewCost < MoveCosts[Neighbor])
400вҶ’			{
401вҶ’				MoveCosts.Add(Neighbor, NewCost);
402вҶ’
403вҶ’				// еңЁз§»еҠЁиҢғеӣҙеҶ…жүҚеҠ е…ҘејҖж”ҫеҲ—иЎЁ
404вҶ’				if (NewCost <= MaxRange)
405вҶ’				{
406вҶ’					OpenList.Add(Neighbor);
407вҶ’				}
408вҶ’			}
409вҶ’		}
410вҶ’	}
411вҶ’
412вҶ’	// ж”¶йӣҶжүҖжңүеҸҜиҫҫж јеӯҗпјҲжҺ’йҷӨиө·зӮ№пјҢеә”з”ЁжңҖе°ҸиҢғеӣҙиҝҮж»Өпјү
413вҶ’	for (auto& Pair : MoveCosts)
414вҶ’	{
415вҶ’		if (Pair.Key != Center && Pair.Value >= MinRange && Pair.Value <= MaxRange)
416вҶ’		{
417вҶ’			ReachableTiles.Add(Pair.Key);
418вҶ’		}
419вҶ’	}
420вҶ’
421вҶ’	return ReachableTiles;
422вҶ’}
