434вҶ’TArray<ALFPHexTile*> ALFPHexGridManager::FindPath(ALFPHexTile* Start, ALFPHexTile* End)
435вҶ’{
436вҶ’	TArray<ALFPHexTile*> Path;
437вҶ’
438вҶ’	// йӘҢиҜҒиҫ“е…Ҙжңүж•ҲжҖ§
439вҶ’	if (!Start || !End || !End->IsWalkable())
440вҶ’	{
441вҶ’		UE_LOG(LogTemp, Warning, TEXT("FindPath: Invalid start or end tile"));
442вҶ’		return Path;
443вҶ’	}
444вҶ’
445вҶ’	// еҰӮжһңиө·зӮ№е’Ңз»ҲзӮ№зӣёеҗҢ
446вҶ’	if (Start == End) {
447вҶ’		Path.Add(Start);
448вҶ’		UE_LOG(LogTemp, Log, TEXT("FindPath: Start and end are the same tile"));
449вҶ’		return Path;
450вҶ’	}
451вҶ’
452вҶ’	// еҜ»и·Ҝж•°жҚ®з»“жһ„
453вҶ’	TMap<ALFPHexTile*, ALFPHexTile*> ParentMap;
454вҶ’	TMap<ALFPHexTile*, float> GScoreMap;  // е®һйҷ…з§»еҠЁд»Јд»·
455вҶ’	TSet<ALFPHexTile*> OpenSet;
456вҶ’	TSet<ALFPHexTile*> ClosedSet;
457вҶ’
458вҶ’	// еҲқе§ӢеҢ–иө·зӮ№
459вҶ’	OpenSet.Add(Start);
460вҶ’	GScoreMap.Add(Start, 0.0f);
461вҶ’	ParentMap.Add(Start, nullptr);
462вҶ’
463вҶ’	bool bPathFound = false;
464вҶ’
465вҶ’	while (!OpenSet.IsEmpty())
466вҶ’	{
467вҶ’		// иҺ·еҸ–ејҖж”ҫйӣҶдёӯFеҖјжңҖе°Ҹзҡ„иҠӮзӮ№
468вҶ’		ALFPHexTile* Current = nullptr;
469вҶ’		float LowestF = TNumericLimits<float>::Max();
470вҶ’
471вҶ’		for (ALFPHexTile* Tile : OpenSet)
472вҶ’		{
473вҶ’			const float G = GScoreMap[Tile];
474вҶ’			const float H = FLFPHexCoordinates::Distance(Tile->GetCoordinates(), End->GetCoordinates());
475вҶ’			const float F = G + H;
476вҶ’
477вҶ’			if (F < LowestF)
478вҶ’			{
479вҶ’				LowestF = F;
480вҶ’				Current = Tile;
481вҶ’			}
482вҶ’		}
483вҶ’
484вҶ’		// еҲ°иҫҫз»ҲзӮ№
485вҶ’		if (Current == End)
486вҶ’		{
487вҶ’			bPathFound = true;
488вҶ’			ALFPHexTile* PathNode = End;
489вҶ’			while (PathNode)
490вҶ’			{
491вҶ’				Path.Add(PathNode);
492вҶ’				PathNode = ParentMap[PathNode];
493вҶ’			}
494вҶ’			Algo::Reverse(Path);
495вҶ’			break;
496вҶ’		}
497вҶ’
498вҶ’		// з§»еҠЁиҠӮзӮ№еҲ°е…ій—ӯйӣҶ
499вҶ’		OpenSet.Remove(Current);
500вҶ’		ClosedSet.Add(Current);
501вҶ’
502вҶ’		// йҒҚеҺҶжүҖжңүйӮ»еұ…
503вҶ’		for (const FLFPHexCoordinates& Dir : HexDirections)
504вҶ’		{
505вҶ’			FLFPHexCoordinates NeighborCoords = Current->GetCoordinates();
506вҶ’			NeighborCoords.Q += Dir.Q;
507вҶ’			NeighborCoords.R += Dir.R;
508вҶ’			NeighborCoords.S = -NeighborCoords.Q - NeighborCoords.R;  // йҮҚж–°и®Ўз®—з«Ӣж–№еқҗж Ү
509вҶ’
510вҶ’			ALFPHexTile* Neighbor = GetTileAtCoordinates(NeighborCoords);
511вҶ’
512вҶ’			// и·іиҝҮж— ж•ҲйӮ»еұ…
513вҶ’			if (!Neighbor ||
514вҶ’				!Neighbor->IsWalkable() ||
515вҶ’				Neighbor->IsOccupied() ||
516вҶ’				ClosedSet.Contains(Neighbor))
517вҶ’			{
518вҶ’				continue;
519вҶ’			}
520вҶ’
521вҶ’			// и®Ўз®—ж–°GеҖјпјҲдҪҝз”Ёең°еҪўз§»еҠЁд»Јд»·пјү
522вҶ’			const float TentativeG = GScoreMap[Current] + (float)Neighbor->GetMovementCost();
523вҶ’
524вҶ’			// еҸ‘зҺ°ж–°иҠӮзӮ№жҲ–жүҫеҲ°жӣҙзҹӯи·Ҝеҫ„
525вҶ’			if (!OpenSet.Contains(Neighbor) || TentativeG < GScoreMap[Neighbor])
526вҶ’			{
527вҶ’				ParentMap.Add(Neighbor, Current);
528вҶ’				GScoreMap.Add(Neighbor, TentativeG);
529вҶ’
530вҶ’				if (!OpenSet.Contains(Neighbor)) {
531вҶ’					OpenSet.Add(Neighbor);
532вҶ’				}
533вҶ’			}
534вҶ’		}
535вҶ’	}
536вҶ’
537вҶ’	Path.Remove(Start);
538вҶ’	// и°ғиҜ•з»ҳеҲ¶и·Ҝеҫ„
539вҶ’	//DrawDebugPath(Path, bPathFound);
540вҶ’
541вҶ’	if (bPathFound) {
542вҶ’		UE_LOG(LogTemp, Log, TEXT("FindPath: Found path with %d tiles"), Path.Num());
543вҶ’	}
544вҶ’	else {
545вҶ’		UE_LOG(LogTemp, Warning, TEXT("FindPath: No valid path found"));
546вҶ’	}
547вҶ’
548вҶ’	return Path;
549вҶ’}
