551вҶ’void ALFPHexGridManager::DrawDebugHexagon(const FVector& Center, FColor Color) const
552вҶ’{
553вҶ’	const float AngleStep = 60.0f;
554вҶ’	const float HorizontalRadius = HexSize; // ж°ҙе№іж–№еҗ‘еҚҠеҫ„дёҚеҸҳ
555вҶ’	const float VerticalRadius = HexSize * VerticalScale; // еһӮзӣҙж–№еҗ‘еҚҠеҫ„зј©ж”ҫ
556вҶ’
557вҶ’	// ж·»еҠ  30В° еҒҸз§»пјҢдҪҝе…ӯиҫ№еҪўжӯЈзЎ®жңқеҗ‘
558вҶ’	const float AngleOffset = 30.0f;
559вҶ’
560вҶ’	TArray<FVector> Points;
561вҶ’	for (int32 i = 0; i < 6; i++)
562вҶ’	{
563вҶ’		// ж·»еҠ  30В° еҒҸз§»
564вҶ’		float Angle = FMath::DegreesToRadians(AngleStep * i + AngleOffset);
565вҶ’		FVector Point(
566вҶ’			Center.X + HorizontalRadius * FMath::Cos(Angle),
567вҶ’			Center.Y + VerticalRadius * FMath::Sin(Angle), // еә”з”ЁеһӮзӣҙзј©ж”ҫ
568вҶ’			Center.Z
569вҶ’		);
570вҶ’		Points.Add(Point);
571вҶ’	}
572вҶ’
573вҶ’	// иҝһжҺҘзӮ№еҪўжҲҗе…ӯиҫ№еҪў
574вҶ’	for (int32 i = 0; i < 6; i++)
575вҶ’	{
576вҶ’		int32 NextIndex = (i + 1) % 6;
577вҶ’		DrawDebugLine(GetWorld(), Points[i], Points[NextIndex], Color, false, -1, 0, 2);
578вҶ’	}
579вҶ’}
