695вҶ’// дё–з•Ңеқҗж ҮиҪ¬жҚўдёәе…ӯиҫ№еҪўзҪ‘ж јеқҗж Ү
696вҶ’FVector2D ALFPHexGridManager::WorldToHexGridPosition(const FVector& WorldPosition, float InHexSize, float InVerticalScale)
697вҶ’{
698вҶ’	// е°–йЎ¶е…ӯиҫ№еҪўеёғеұҖеҸӮж•°
699вҶ’	const float HorizontalSpacing = InHexSize * 1.5f * InVerticalScale; // ж°ҙе№ій—ҙи·қпјҲеә”з”ЁеһӮзӣҙзј©ж”ҫпјү
700вҶ’	const float VerticalSpacing = InHexSize * FMath::Sqrt(3.0f); // еһӮзӣҙй—ҙи·қ
701вҶ’
702вҶ’	// и®Ўз®—еҺҹзӮ№дҪҚзҪ®
703вҶ’	FVector GridOrigin = GetActorLocation();
704вҶ’
705вҶ’	// и®Ўз®—зӣёеҜ№дәҺзҪ‘ж јеҺҹзӮ№зҡ„дҪҚзҪ®
706вҶ’	float RelX = WorldPosition.X - GridOrigin.X;
707вҶ’	float RelY = WorldPosition.Y - GridOrigin.Y;
708вҶ’
709вҶ’	// иҪ¬жҚўдёәе…ӯиҫ№еҪўзҪ‘ж јеқҗж ҮпјҲиҝ‘дјјпјү
710вҶ’	return FVector2D(
711вҶ’		RelX / HorizontalSpacing,
712вҶ’		RelY / VerticalSpacing
713вҶ’	);
714вҶ’}
