717вҶ’FLFPHexCoordinates ALFPHexGridManager::PixelToHexCoordinates(const FVector2D& PixelPosition, float InHexSize)
718вҶ’{
719вҶ’    // иҺ·еҸ–еғҸзҙ еҖј
720вҶ’    float x = PixelPosition.X;
721вҶ’    float y = PixelPosition.Y;
722вҶ’
723вҶ’    // иҪ¬жҚўдёәз«Ӣж–№еқҗж Ү - е°–йЎ¶е…ӯиҫ№еҪўе…¬ејҸ
724вҶ’    float q = (2.0f / 3.0f) * x;
725вҶ’    float r = (-1.0f / 3.0f) * x + (FMath::Sqrt(3.0f) / 3.0f) * y;
726вҶ’
727вҶ’    // дҪҝз”ЁдјҳеҢ–еҗҺзҡ„еӣӣиҲҚдә”е…ҘеҲ°жңҖиҝ‘еқҗж Ү
728вҶ’    return RoundToHex(q, r);
729вҶ’}
