731вҶ’// еҲӨж–ӯзӮ№жҳҜеҗҰеңЁе…ӯиҫ№еҪўеҶ…
732вҶ’bool ALFPHexGridManager::IsPointInHexagon(const FVector2D& Point, const FVector2D& Center, float InHexSize)
733вҶ’{
734вҶ’	// еқҗж ҮиҪ¬жҚўдёәзӣёеҜ№дәҺе…ӯиҫ№еҪўдёӯеҝғзҡ„еҚ•дҪҚеҗ‘йҮҸ
735вҶ’	FVector2D relPoint = Point - Center;
736вҶ’
737вҶ’	// е°–йЎ¶е…ӯиҫ№еҪўзҡ„йЎ¶зӮ№дҪҚзҪ®пјҲд»Һ0еәҰејҖе§Ӣпјү
738вҶ’	static const TArray<FVector2D> vertices = [] {
739вҶ’		TArray<FVector2D> result;
740вҶ’		for (int i = 0; i < 6; i++) {
741вҶ’			float angle_deg = 60 * i; // е°–йЎ¶е…ӯиҫ№еҪўд»Һ0еәҰејҖе§Ӣ
742вҶ’			float angle_rad = FMath::DegreesToRadians(angle_deg);
743вҶ’			result.Add(FVector2D(FMath::Cos(angle_rad), FMath::Sin(angle_rad)));
744вҶ’		}
745вҶ’		return result;
746вҶ’		}();
747вҶ’
748вҶ’	// еҲӨж–ӯзӮ№жҳҜеҗҰеңЁе…ӯиҫ№еҪўеҶ…пјҲдҪҝз”Ёе°„зәҝжі•пјү
749вҶ’	int crossings = 0;
750вҶ’	for (int i = 0; i < 6; i++) {
751вҶ’		int j = (i + 1) % 6;
752вҶ’		FVector2D v1 = vertices[i] * InHexSize;
753вҶ’		FVector2D v2 = vertices[j] * InHexSize;
754вҶ’
755вҶ’		// жЈҖжөӢиҫ№жҳҜеҗҰи·Ёи¶Ҡyеқҗж Ү
756вҶ’		if ((v1.Y > relPoint.Y) != (v2.Y > relPoint.Y)) {
757вҶ’			// и®Ўз®—дәӨзӮ№xеқҗж Ү
758вҶ’			float intersectX = (v2.X - v1.X) * (relPoint.Y - v1.Y) / (v2.Y - v1.Y) + v1.X;
759вҶ’
760вҶ’			// еҰӮжһңдәӨзӮ№еңЁзӮ№зҡ„еҸідҫ§
761вҶ’			if (relPoint.X < intersectX) {
762вҶ’				crossings++;
763вҶ’			}
764вҶ’		}
765вҶ’	}
766вҶ’
767вҶ’	// еҘҮж•°ж¬Ўи·Ёи¶ҠиЎЁзӨәеңЁеҶ…йғЁ
768вҶ’	return (crossings % 2 == 1);
769вҶ’}
