771вҶ’void ALFPHexGridManager::UpdateGridSpriteWithTiles(EPlayControlState CurrentControlState, TArray<ALFPHexTile*>& Tiles)
772вҶ’{
773вҶ’	ResetGridSprite();
774вҶ’	switch (CurrentControlState)
775вҶ’	{
