778вҶ’		for (ALFPHexTile* Tile : Tiles)
779вҶ’		{
780вҶ’			Tile->SetRangeSprite(EUnitRange::UR_Move);
781вҶ’		}
782вҶ’		break;
783вҶ’	case EPlayControlState::SkillReleaseState:
784вҶ’		for (ALFPHexTile* Tile : Tiles)
785вҶ’		{
786вҶ’			Tile->SetRangeSprite(EUnitRange::UR_SkillEffect);
787вҶ’		}
788вҶ’		break;
789вҶ’	default:
790вҶ’		break;
791вҶ’	}
792вҶ’}
