794вҶ’void ALFPHexGridManager::UpdateGridSpriteWithCoords(EPlayControlState CurrentControlState, TArray<FLFPHexCoordinates>& Coords)
795вҶ’{
796вҶ’	ResetGridSprite();
797вҶ’	switch (CurrentControlState)
798вҶ’	{
799вҶ’	case EPlayControlState::MoveState:
800вҶ’		// й«ҳдә®жҳҫзӨәиҝҷдәӣж јеӯҗ
801вҶ’		for (FLFPHexCoordinates Coord : Coords)
802вҶ’		{
803вҶ’			ALFPHexTile* Tile = GetTileAtCoordinates(Coord);
804вҶ’			if (Tile)
805вҶ’			{
806вҶ’				Tile->SetRangeSprite(EUnitRange::UR_Move);
807вҶ’			}
808вҶ’		}
809вҶ’		break;
810вҶ’	case EPlayControlState::SkillReleaseState:
811вҶ’		for (FLFPHexCoordinates Coord : Coords)
812вҶ’		{
813вҶ’			ALFPHexTile* Tile = GetTileAtCoordinates(Coord);
814вҶ’			if (Tile)
815вҶ’			{
816вҶ’				Tile->SetRangeSprite(EUnitRange::UR_SkillEffect);
817вҶ’			}
818вҶ’		}
819вҶ’		break;
820вҶ’	default:
821вҶ’		break;
822вҶ’	}
823вҶ’}
