825вҶ’void ALFPHexGridManager::ResetGridSprite()
826вҶ’{
827вҶ’	for (auto& TilePair : GridMap)
828вҶ’	{
829вҶ’		if (TilePair.Value)
830вҶ’		{
831вҶ’			TilePair.Value->SetRangeSprite(EUnitRange::UR_Default);
832вҶ’		}
833вҶ’	}
834вҶ’}
