581вҶ’        if (MovementRangeTiles.Contains(Tile))
582вҶ’        {
583вҶ’            SelectedTile = Tile;
584вҶ’            ShowPathToSelectedTile();
585вҶ’        }
586вҶ’        else
587вҶ’        {
588вҶ’            SelectedTile = Tile;
589вҶ’            // жё…йҷӨд№ӢеүҚй«ҳдә®жҳҫзӨәзҡ„и·Ҝеҫ„
590вҶ’            HidePathToRange();
591вҶ’        }
592вҶ’        break;
593вҶ’    case EPlayControlState::SkillReleaseState:
