625вҶ’void ALFPTacticsPlayerController::ShowUnitRange(EUnitRange UnitRange)
626вҶ’{
627вҶ’    if (!SelectedUnit || !GridManager) return;
628вҶ’
629вҶ’    GridManager->ResetGridSprite();
630вҶ’    /*for (ALFPHexTile* Tile : CacheRangeTiles)
631вҶ’    {
632вҶ’        Tile->SetRangeSprite(EUnitRange::UR_Default);
633вҶ’    }*/
634вҶ’    CacheRangeTiles.Empty();
635вҶ’    MovementRangeTiles.Empty();
636вҶ’
637вҶ’    switch (UnitRange)
638вҶ’    {
639вҶ’    case EUnitRange::UR_Default:
640вҶ’        break;
641вҶ’    case EUnitRange::UR_Move:
642вҶ’	{
643вҶ’        // иҺ·еҸ–еҸҜз§»еҠЁиҢғеӣҙ
644вҶ’		ALFPHexTile* UnitTile = GridManager->GetTileAtCoordinates(SelectedUnit->GetCurrentCoordinates());
645вҶ’		if (UnitTile)
646вҶ’		{
647вҶ’			CacheRangeTiles= MovementRangeTiles = GridManager->GetTilesInRange(UnitTile, SelectedUnit->GetMovementRange());
648вҶ’			// й«ҳдә®жҳҫзӨәиҝҷдәӣж јеӯҗ
649вҶ’            GridManager->UpdateGridSpriteWithTiles(CurrentControlState, MovementRangeTiles);
650вҶ’		}
651вҶ’        break;
652вҶ’	}
653вҶ’    case EUnitRange::UR_Attack:
654вҶ’		// иҺ·еҸ–еҸҜж”»еҮ»иҢғеӣҙ
655вҶ’        CacheRangeTiles = SelectedUnit->GetAttackRangeTiles();
656вҶ’		// й«ҳдә®жҳҫзӨәиҝҷдәӣж јеӯҗ
657вҶ’		for (ALFPHexTile* Tile : CacheRangeTiles)
658вҶ’		{
659вҶ’			Tile->SetRangeSprite(EUnitRange::UR_Attack);
660вҶ’		}
661вҶ’        break;
662вҶ’    default:
663вҶ’        break;
664вҶ’    }
665вҶ’}
